const SRE_H_LOGS={base:'font-family: "Segoe UI", Tahoma, sans-serif; font-size: 10px; font-weight: bold; padding: 2px 6px; border-radius: 3px;',astro:'background: #D4AF37; color: #000000; border: 1px solid #B8860B; border: 1px solid #00c853;',display:'background: #008080; color: #ffffff; border: 1px solid #004d4d; border: 1px solid #00c853;'};document.addEventListener("DOMContentLoaded",function(){const systemInit=new Promise((resolve)=>{const bannerImg=document.getElementById("Banner");if(bannerImg){const banners=["https://gitechnolo.github.io/biotechproject/Biotech-file/images/Biotech-menu/banner1.avif","https://gitechnolo.github.io/biotechproject/Biotech-file/images/Biotech-menu/banner2.avif","https://gitechnolo.github.io/biotechproject/Biotech-file/images/Biotech-menu/banner3.avif","https://gitechnolo.github.io/biotechproject/Biotech-file/images/Biotech-menu/banner4.avif"];banners.map(src=>{const img=new Image();img.src=src;return img});let bnrCntr=0;setInterval(()=>{bannerImg.classList.add("banner-fade-out");setTimeout(()=>{bnrCntr=(bnrCntr+1)%banners.length;bannerImg.src=banners[bnrCntr];bannerImg.classList.remove("banner-fade-out")},500)},3500)}
const msgContainer=document.getElementById("holidayMsg");if(msgContainer){const holiday=getNextHoliday();msgContainer.innerHTML=`<p class="holiday-countdown ${holiday.style}">${holiday.msg}</p>`}
resolve("DOM and Assets initialized.")});systemInit.then(()=>{return new Promise(resolve=>window.addEventListener("load",resolve))}).then(()=>{triggerHumanSync()})});function triggerHumanSync(){const logStyle="color: #B5EAD7; font-family: 'Courier New', monospace; background: #1a1a1a; padding: 2px 5px; border-radius: 3px; border: 1px solid rgba(0, 230, 118, 0.3); text-shadow: 1px 1px 2px rgba(137, 43, 226, 0.568);";console.log("%c 🐂 SYNC BiotechProject: Mastering the beast. Passion and logic synchronized within the labyrinth.",logStyle)}
function getEaster(year){const a=year%19,b=Math.floor(year/100),c=year%100;const d=Math.floor(b/4),e=b%4,f=Math.floor((b+8)/25);const g=Math.floor((b-f+1)/3),h=(19*a+b-d-g+15)%30;const i=Math.floor(c/4),k=c%4,l=(32+2*e+2*i-h-k)%7;const m=Math.floor((a+11*h+22*l)/451);const month=Math.floor((h+l-7*m+114)/31);const day=((h+l-7*m+114)%31)+1;return{month:month-1,day:day}}
function getNextHoliday(){const now=new Date();const today=new Date(now.getFullYear(),now.getMonth(),now.getDate());const currentYear=today.getFullYear();console.log(`%c 🌕 ASTRO %c Syncing dynamic cycles for ${currentYear}`,SRE_H_LOGS.astro+SRE_H_LOGS.base,"color: #888; margin-left: 5px;");const holidaySchema=[{name:"St. Patrick's Day",month:2,day:17,style:"st-patrick",wish:"Happy St. Paddy's!",icon:"☘️",isDynamic:!1},{name:"Easter",style:"easter",wish:"Happy Easter!",icon:"🐣",isDynamic:!0},{name:"4th of July",month:6,day:4,style:"july4",wish:"Happy Independence Day!",icon:"🎆",isDynamic:!1},{name:"Halloween",month:9,day:31,style:"halloween",wish:"Spooky Halloween!",icon:"🎃",isDynamic:!1},{name:"Christmas",month:11,day:25,style:"natale",wish:"Merry Christmas!",icon:"🎄",isDynamic:!1}];const upcomingHolidays=holidaySchema.map(h=>{let date;if(h.isDynamic){const dData=getEaster(currentYear);date=new Date(currentYear,dData.month,dData.day);if(date<today){const nextYearData=getEaster(currentYear+1);date=new Date(currentYear+1,nextYearData.month,nextYearData.day)}}else{date=new Date(currentYear,h.month,h.day);if(date<today){date=new Date(currentYear+1,h.month,h.day)}}
return{...h,date}}).sort((a,b)=>a.date-b.date);const nextHoliday=upcomingHolidays[0];const daysLeft=Math.ceil((nextHoliday.date-today)/86400000);const isToday=daysLeft===0;console.log(`%c${nextHoliday.icon} BiotechHoliday%c ${nextHoliday.name}: ${isToday ? 'ACTIVE' : daysLeft + 'd left'}`,SRE_H_LOGS.display+SRE_H_LOGS.base,"color: #bcbcbc; margin-left: 5px;");return{msg:isToday?`${nextHoliday.icon} <span class="holiday-name ${nextHoliday.style}">${nextHoliday.wish}</span>`:`Only ${daysLeft} days until ${nextHoliday.icon} <span class="holiday-name ${nextHoliday.style}">${nextHoliday.name}</span>!`,style:nextHoliday.style}}
function turnOnLight(){const img=document.getElementById('myImage');if(img){img.src='https://gitechnolo.github.io/biotechproject/Biotech-file/images/pic_bulbon.avif';img.classList.add('bulb-glow')}}
function turnOffLight(){const img=document.getElementById('myImage');if(img){img.src='https://gitechnolo.github.io/biotechproject/Biotech-file/images/pic_bulboff.avif';img.classList.remove('bulb-glow')}}(function(){const initFadeInSequence=()=>{const lines=document.querySelectorAll(".type-line");let currentLineIndex=0;const showNextLine=()=>{if(currentLineIndex>=lines.length)return;const line=lines[currentLineIndex];if(line.textContent.trim().length===0){setTimeout(showNextLine,50);return}
line.classList.add("is-visible");currentLineIndex++;setTimeout(showNextLine,500)};const observer=new IntersectionObserver((entries)=>{if(entries[0].isIntersecting){showNextLine();observer.disconnect()}},{threshold:0.2});const terminalWindow=document.querySelector(".terminal-window");if(terminalWindow)observer.observe(terminalWindow);};window.addEventListener("load",initFadeInSequence)})()